const hue = (params.triggerCount * 37) % 360;
return [
  { type: 'rect', x: 40, y: 40, width: 160, height: 100, color: `hsl(${hue},70%,60%)` },
  { type: 'circle', x: 350, y: 200, radius: 80, color: `hsl(${(hue+120)%360},70%,60%)` },
  { type: 'text', text: 'Canvas', x: '50%', y: '78%', color: `hsl(${(hue+240)%360},70%,40%)`, font: { size: '12%', weight: 'bold', family: 'monospace' } }
];
